async function* executeSingleAgent(
  agentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  activeAgents: string[] = [],
  context: ProviderChatRequest["context"] = []
): AsyncGenerator<StreamResponse> {
  const provider = globalRegistry.getProviderForAgent(agentId);
  const agentConfig = globalRegistry.getAgent(agentId);

  if (!provider || !agentConfig) {
    yield {
      type: "error",
      error: `Agent '${agentId}' not found or provider not available`,
    };
    return;
  }

  // Handle special commands
  if (command?.command === "capture_screen") {
    yield* handleScreenCapture(agentId, request, command, abortController, debugMode);
    return;
  }

  // Build provider request
  const providerRequest: ProviderChatRequest = {
    message: request.message,
    sessionId: request.sessionId,
    requestId: request.requestId,
    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
    ...(context.length ? { context } : {}),
  };

  let pendingContext = context;
  let invocation = 0;
  while (!abortController.signal.aborted) {
    const toolResults: ProviderChatRequest["context"] = [];
    let delegated = false;

    // Re-invoke the delegating agent after each delegated tool result. The
    // result is supplied as context rather than exposed as a new user request.
    for await (const response of provider.executeChat({
      ...providerRequest,
      ...(pendingContext.length ? { context: pendingContext } : {}),
      requestId: invocation === 0 ? request.requestId : `${request.requestId}:resume:${invocation}`,
    }, {
      debugMode,
      abortController,
      temperature: agentConfig.config?.temperature,
      maxTokens: agentConfig.config?.maxTokens,
    })) {
    // Convert provider response to stream response
    const chatRoomMessage = createChatRoomMessage(response, agentId);

    if (chatRoomMessage) {
      // Send as chat room protocol message
      yield {
        type: "claude_json",
        data: {
          type: "chat_room_message",
          message: chatRoomMessage,
          session_id: request.sessionId,
        },
      };
    }

    // Also send original response format for compatibility
    if (response.type === "text") {
      yield {
        type: "claude_json",
        data: {
          type: "assistant",
          content: response.content,
          model: response.metadata?.model,
        },
      };
      if (response.type === "tool_use" && response.toolName === "delegate_task") {
        const toolUseId = response.toolUseId || `${request.requestId}:delegate:${invocation}`;
        const input = response.toolInput as { agent_id?: unknown; instructions?: unknown } | undefined;
        const delegatedAgentId = typeof input?.agent_id === "string" ? input.agent_id : "";
        const instructions = typeof input?.instructions === "string" ? input.instructions : "";

        yield delegationToolUse(toolUseId, response.toolInput, request.sessionId);

        let result: DelegationResult;
        if (!delegatedAgentId || !globalRegistry.getAgent(delegatedAgentId) || !globalRegistry.getProviderForAgent(delegatedAgentId)) {
          const message = `Agent '${delegatedAgentId || "(missing agent_id)"}' not found or provider not available`;
          yield { type: "error", error: message };
          result = { content: message, isError: true };
        } else if (activeAgents.includes(delegatedAgentId) || delegatedAgentId === agentId) {
          const message = `Circular delegation detected: ${[...activeAgents, agentId, delegatedAgentId].join(" -> ")}`;
          yield { type: "error", error: message };
          result = { content: message, isError: true };
        } else {
          result = await collectDelegatedAgentResult(
            delegatedAgentId,
            instructions,
            request,
            abortController,
            debugMode,
            [...activeAgents, agentId],
          );
        }

        const toolResult = JSON.stringify({
          type: "tool_result",
          is_error: result.isError,
          content: result.content || "The delegated agent completed without producing text.",
          tool_use_id: toolUseId,
        });
        yield delegationToolResult(toolUseId, toolResult, request.sessionId, result.isError);
        toolResults.push({ role: "user", content: toolResult });
        delegated = true;
      } else if (response.type === "done") {
        // A delegation requires another turn so the caller can consume its
        // tool_result. Ordinary completions finish this agent invocation.
        if (!delegated) {
          yield { type: "done" };
          return;
        }
      } else if (response.type === "error") {
        yield { type: "error", error: response.error };
        return;
      }
    }
    }

    if (!delegated) return;
    pendingContext = toolResults;
    invocation++;
  }
}

interface DelegationResult {
  content: string;
  isError: boolean;
}

function delegationToolUse(toolUseId: string, input: unknown, sessionId?: string): StreamResponse {
  return { type: "claude_json", data: { type: "assistant", message: { content: [{ type: "tool_use", id: toolUseId, name: "delegate_task", input }] }, session_id: sessionId } };
}

function delegationToolResult(toolUseId: string, content: string, sessionId: string | undefined, isError: boolean): StreamResponse {
  return { type: "claude_json", data: { type: "user", message: { content: [{ type: "tool_result", tool_use_id: toolUseId, content, is_error: isError }] }, session_id: sessionId } };
}

